// Prefer a copy constructor over Cloneable to control deep vs shallow copy.
public final class GameUnit {
    private final String type;
    private final List<String> abilities;
    private int hp;

    public GameUnit(String type, List<String> abilities, int hp) {
        this.type = type; this.abilities = new ArrayList<>(abilities); this.hp = hp;
    }
    // copy constructor = explicit prototype
    public GameUnit(GameUnit src) {
        this(src.type, src.abilities, src.hp);   // deep-copies the list
    }
    public GameUnit withHp(int newHp) {
        GameUnit copy = new GameUnit(this); copy.hp = newHp; return copy;
    }
}

