class VideoConverterFacade {
    public File convert(String filename, String targetFormat) {
        VideoFile file = new VideoFile(filename);
        Codec source = CodecFactory.extract(file);
        Codec dest = targetFormat.equals("mp4") ? new Mp4Codec() : new OggCodec();
        BitrateReader buffer = BitrateReader.read(file, source);
        BitrateReader result = BitrateReader.convert(buffer, dest);
        return new AudioMixer().fix(result);   // hides 5 subsystem classes
    }
}

