interface FsNode { long size(); }

class FileNode implements FsNode {
    private final long bytes;
    FileNode(long bytes) { this.bytes = bytes; }
    public long size() { return bytes; }
}

class DirNode implements FsNode {
    private final List<FsNode> children = new ArrayList<>();
    public DirNode add(FsNode n) { children.add(n); return this; }
    public long size() {                       // recurse uniformly
        return children.stream().mapToLong(FsNode::size).sum();
    }
}

