interface Command { void execute(); void undo(); }

class InsertTextCommand implements Command {
    private final Document doc; private final String text; private final int pos;
    InsertTextCommand(Document doc, String text, int pos) {
        this.doc = doc; this.text = text; this.pos = pos;
    }
    public void execute() { doc.insert(pos, text); }
    public void undo() { doc.delete(pos, text.length()); }
}

class Editor {
    private final Deque<Command> history = new ArrayDeque<>();
    public void run(Command c) { c.execute(); history.push(c); }
    public void undo() { if (!history.isEmpty()) history.pop().undo(); }
}

abstract class Handler {
    private Handler next;
    public Handler setNext(Handler next) { this.next = next; return next; }
    public final void handle(Request req) {
        if (canHandle(req)) process(req);
        else if (next != null) next.handle(req);
        else throw new IllegalStateException("Unhandled: " + req);
    }
    protected abstract boolean canHandle(Request req);
    protected abstract void process(Request req);
}

class AuthHandler extends Handler {
    protected boolean canHandle(Request r) { return !r.isAuthenticated(); }
    protected void process(Request r) { r.reject(401); }
}

