// Strategy: one interchangeable algorithm per channel.
interface NotificationChannel {
    void send(Notification n);
    boolean supports(Channel type);
}

class EmailChannel implements NotificationChannel {
    public boolean supports(Channel t) { return t == Channel.EMAIL; }
    public void send(Notification n) { /* SES call */ }
}
class SmsChannel implements NotificationChannel {
    public boolean supports(Channel t) { return t == Channel.SMS; }
    public void send(Notification n) { /* Twilio call */ }
}

// Observer: the dispatcher subscribes to domain events and fans out,
// isolating per-channel failures so one outage cannot poison the rest.
class NotificationDispatcher implements OrderObserver {
    private final List<NotificationChannel> channels;
    private final UserPreferences prefs;

    NotificationDispatcher(List<NotificationChannel> channels, UserPreferences prefs) {
        this.channels = channels; this.prefs = prefs;
    }
    public void onPlaced(Order order) {
        Notification n = Notification.confirmation(order);
        for (Channel type : prefs.channelsFor(order.userId())) {
            channels.stream().filter(c -> c.supports(type)).findFirst()
                .ifPresent(c -> safeSend(c, n));   // each channel isolated
        }
    }
    private void safeSend(NotificationChannel c, Notification n) {
        try { c.send(n); }
        catch (Exception e) { log.error("channel failed, continuing", e); }
    }
}

// BROKEN: no volatile -> partially constructed object can leak.
class Config {
    private static Config instance;            // missing volatile
    static Config get() {
        if (instance == null) {
            synchronized (Config.class) {
                if (instance == null) instance = new Config(); // reorder hazard
            }
        }
        return instance;
    }
}
// CORRECT options: mark the field volatile, or use the initialization-on-demand
// holder idiom, which is lazy and thread-safe with no synchronization:
class ConfigOk {
    private ConfigOk() {}
    private static class Holder { static final ConfigOk I = new ConfigOk(); }
    static ConfigOk get() { return Holder.I; }
}

