import java.util.*;

interface DiscountStrategy {
    long applyTo(long subtotalCents);   // returns amount AFTER discount
}

class NoDiscount implements DiscountStrategy {
    public long applyTo(long s) { return s; }
}

class PercentDiscount implements DiscountStrategy {
    private final int percent;
    PercentDiscount(int percent) { this.percent = percent; }
    public long applyTo(long s) { return s - (s * percent / 100); }
}

class Checkout {
    private final DiscountStrategy discount;
    Checkout(DiscountStrategy discount) {
        this.discount = Objects.requireNonNull(discount);
    }
    long total(long subtotalCents) { return discount.applyTo(subtotalCents); }
}

// Registry replaces the switch: adding a promotion = one put(), no edits elsewhere.
class DiscountRegistry {
    private final Map<String, DiscountStrategy> strategies = new HashMap<>();
    DiscountRegistry() {
        strategies.put("NONE", new NoDiscount());
        strategies.put("PERCENT_10", new PercentDiscount(10));
        strategies.put("BLACK_FRIDAY", new PercentDiscount(40));
        strategies.put("LOYALTY", s -> s - 500);   // lambda strategy
    }
    DiscountStrategy forCode(String code) {
        return strategies.getOrDefault(code, new NoDiscount());
    }
}

class Demo {
    public static void main(String[] args) {
        var registry = new DiscountRegistry();
        var checkout = new Checkout(registry.forCode("BLACK_FRIDAY"));
        System.out.println(checkout.total(10000)); // 6000 cents
    }
}

import java.util.*;
import java.util.concurrent.*;
import java.util.function.Consumer;

public class EventBus {
    // CopyOnWriteArrayList: safe to iterate while others mutate it.
    private final Map<Class<?>, List<Consumer<?>>> listeners = new ConcurrentHashMap<>();

    public interface Subscription extends AutoCloseable {
        void close();   // narrow checked exception away
    }

    public <T> Subscription subscribe(Class<T> type, Consumer<T> listener) {
        listeners.computeIfAbsent(type, k -> new CopyOnWriteArrayList<>()).add(listener);
        // returning a handle is what prevents the lapsed-listener leak
        return () -> {
            List<Consumer<?>> l = listeners.get(type);
            if (l != null) l.remove(listener);
        };
    }

    @SuppressWarnings("unchecked")
    public <T> void publish(T event) {
        List<Consumer<?>> l = listeners.get(event.getClass());
        if (l == null) return;
        for (Consumer<?> raw : l) {
            try {
                ((Consumer<T>) raw).accept(event);   // isolate each listener
            } catch (RuntimeException e) {
                System.err.println("listener failed, continuing: " + e.getMessage());
            }
        }
    }

    public static void main(String[] args) {
        EventBus bus = new EventBus();
        Subscription sub = bus.subscribe(String.class, s -> System.out.println("got: " + s));
        bus.subscribe(String.class, s -> { throw new RuntimeException("boom"); });
        bus.publish("order-42");   // first listener still fires despite the boom
        sub.close();               // deterministic unsubscribe -> no leak
        bus.publish("order-43");   // first listener no longer receives it
    }
}
